import React, { useState } from 'react';
import api from '../services/api';

export default function CancellationPanel() {
  const [form, setForm] = useState({ rideRequestId: '', cancelledBy: 'PASSENGER', cancellerId: '', reason: '' });
  const [histForm, setHistForm] = useState({ cancellerId: '', cancelledBy: 'PASSENGER' });
  const [result, setResult] = useState(null);
  const [history, setHistory] = useState(null);
  const [loading, setLoading] = useState(false);

  const cancel = async e => {
    e.preventDefault(); setLoading(true); setResult(null);
    try {
      const { data } = await api.post('/api/cancellation/cancel', {
        rideRequestId: parseInt(form.rideRequestId),
        cancelledBy: form.cancelledBy,
        cancellerId: parseInt(form.cancellerId),
        reason: form.reason
      });
      setResult(data);
    } catch (err) { setResult({ message: err.response?.data?.message || 'Error' }); }
    finally { setLoading(false); }
  };

  const fetchHistory = async e => {
    e.preventDefault();
    try {
      const { data } = await api.get('/api/cancellation/history', {
        params: { cancellerId: histForm.cancellerId, cancelledBy: histForm.cancelledBy }
      });
      setHistory(data);
    } catch {}
  };

  const POLICY = [
    { window: '0 – 2 min', penalty: '₹0', label: 'Grace period' },
    { window: '2 – 5 min', penalty: '₹30', label: 'Early cancel' },
    { window: '5 – 15 min', penalty: '₹60', label: 'Mid cancel' },
    { window: '15+ min', penalty: '₹100', label: 'Late cancel' },
    { window: 'Driver cancel', penalty: '₹50', label: 'Flat penalty' },
  ];

  return (
    <>
      {/* Policy table */}
      <div className="panel">
        <div className="panel-header"><h3>Cancellation Policy</h3><span className="badge">Feature 5</span></div>
        <div className="panel-body" style={{ padding: 0 }}>
          <table className="data-table">
            <thead><tr><th>Time Window</th><th>Penalty</th><th>Tier</th></tr></thead>
            <tbody>
              {POLICY.map(p => (
                <tr key={p.window}>
                  <td>{p.window}</td>
                  <td style={{ color: p.penalty === '₹0' ? 'var(--green)' : 'var(--red)', fontWeight: 600 }}>{p.penalty}</td>
                  <td style={{ color: 'var(--text-secondary)', fontSize: 13 }}>{p.label}</td>
                </tr>
              ))}
            </tbody>
          </table>
          <div style={{ padding: '12px 16px', background: 'rgba(201,168,76,0.06)', borderTop: '1px solid var(--border)', fontSize: 13, color: 'var(--gold)' }}>
            ✦ First-time cancellation waiver: penalty is automatically waived for a user's first-ever cancellation.
          </div>
        </div>
      </div>

      {/* Cancel Ride */}
      <div className="panel">
        <div className="panel-header"><h3>Cancel a Ride</h3><span className="badge">POST /api/cancellation/cancel</span></div>
        <div className="panel-body">
          <form onSubmit={cancel}>
            <div className="form-row">
              <div className="form-group"><label>Ride Request ID</label><input placeholder="1" value={form.rideRequestId} onChange={e => setForm({...form, rideRequestId: e.target.value})} /></div>
              <div className="form-group"><label>Canceller ID</label><input placeholder="1" value={form.cancellerId} onChange={e => setForm({...form, cancellerId: e.target.value})} /></div>
            </div>
            <div className="form-row">
              <div className="form-group"><label>Cancelled By</label>
                <select value={form.cancelledBy} onChange={e => setForm({...form, cancelledBy: e.target.value})}>
                  <option value="PASSENGER">Passenger</option>
                  <option value="DRIVER">Driver</option>
                </select>
              </div>
              <div className="form-group"><label>Reason</label><input placeholder="Change of plans" value={form.reason} onChange={e => setForm({...form, reason: e.target.value})} /></div>
            </div>
            <button className="btn-action" type="submit" disabled={loading}>
              {loading && <span className="spinner" />} Cancel Ride
            </button>
          </form>

          {result && (
            <div className="result-card">
              <h4>Cancellation Result</h4>
              <div className="result-row"><span className="rk">Message</span><span className="rv" style={{ fontSize:13 }}>{result.message}</span></div>
              {result.minutesAfterBooking !== undefined && <>
                <div className="result-row"><span className="rk">Minutes After Booking</span><span className="rv">{result.minutesAfterBooking?.toFixed(1)} min</span></div>
                <div className="result-row"><span className="rk">Applied Policy</span><span className="rv" style={{ fontSize:13 }}>{result.appliedPolicyWindow}</span></div>
                <div className="result-row"><span className="rk">Penalty Amount</span>
                  <span className={`rv ${result.penaltyAmount === 0 ? 'success' : 'error'}`}>
                    ₹{result.penaltyAmount} {result.penaltyWaived ? '(WAIVED)' : ''}
                  </span>
                </div>
                {result.waiverReason && <div className="result-row"><span className="rk">Waiver Reason</span><span className="rv success" style={{ fontSize:12 }}>{result.waiverReason}</span></div>}
                <div className="result-row"><span className="rk">Summary</span><span className="rv" style={{ fontSize:12, color:'var(--text-secondary)' }}>{result.summary}</span></div>
              </>}
            </div>
          )}
        </div>
      </div>

      {/* Cancellation History */}
      <div className="panel">
        <div className="panel-header"><h3>Cancellation History</h3><span className="badge">GET /api/cancellation/history</span></div>
        <div className="panel-body">
          <form onSubmit={fetchHistory} style={{ display:'flex', gap:12, flexWrap:'wrap', alignItems:'flex-end' }}>
            <div className="form-group" style={{ marginBottom:0, flex:1, minWidth:120 }}>
              <label>User ID</label>
              <input placeholder="1" value={histForm.cancellerId} onChange={e => setHistForm({...histForm, cancellerId: e.target.value})} />
            </div>
            <div className="form-group" style={{ marginBottom:0, flex:1, minWidth:140 }}>
              <label>Cancelled By</label>
              <select value={histForm.cancelledBy} onChange={e => setHistForm({...histForm, cancelledBy: e.target.value})}>
                <option value="PASSENGER">Passenger</option>
                <option value="DRIVER">Driver</option>
              </select>
            </div>
            <button className="btn-action" type="submit" style={{ marginBottom:1 }}>Load History</button>
          </form>
          {history && (
            <div style={{ marginTop: 20 }}>
              {history.length === 0
                ? <p style={{ color:'var(--text-muted)', fontSize:13 }}>No cancellation history found.</p>
                : <table className="data-table">
                    <thead><tr><th>Ride ID</th><th>By</th><th>Mins</th><th>Penalty</th><th>Waived</th></tr></thead>
                    <tbody>{history.map(h => (
                      <tr key={h.id}>
                        <td>#{h.rideRequestId}</td>
                        <td>{h.cancelledBy}</td>
                        <td>{h.minutesAfterBooking?.toFixed(1)}</td>
                        <td style={{ color:'var(--red)' }}>₹{h.penaltyAmount}</td>
                        <td style={{ color: h.penaltyWaived ? 'var(--green)' : 'var(--text-muted)' }}>{h.penaltyWaived ? 'Yes' : 'No'}</td>
                      </tr>
                    ))}</tbody>
                  </table>
              }
            </div>
          )}
        </div>
      </div>
    </>
  );
}
